import { createContext } from 'react';
import type { CueModalId } from '../core/ports';

export type UseCueSingleResult = {
  dismiss: () => void;
  eligible: boolean;
  modalId: CueModalId;
  mode: 'single';
};

export type UseCueTourResult = {
  closeTour: () => void;
  currentStepKey: string;
  eligible: boolean;
  goBack: () => void;
  goNext: () => void;
  modalId: CueModalId;
  mode: 'tour';
  stepIndex: number;
  totalSteps: number;
};

export type UseCueResult = UseCueSingleResult | UseCueTourResult;

export const CueContext = createContext<UseCueResult | null>(null);
